import{r,o as p,a as l,b as e,d as s,w as t,F as c,e as n,c as a}from"./app.9dea7966.js";import{_ as d}from"./plugin-vue_export-helper.21dcd24c.js";var u="/zopeneditor-about/assets/zapp-rseapi.e541dd7d.png";const h={},m=e("h1",{id:"ebcdic-code-pages-and-mappings-files",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#ebcdic-code-pages-and-mappings-files","aria-hidden":"true"},"#"),n(" EBCDIC code pages and mappings files")],-1),g=n("IBM Z\xAE Open Editor and RSE API Plug-in for Zowe\u2122 CLI (RSE CLI plug-in) can handle EBCDIC code page conversion mappings for MVS and UNIX System Services files. You can set an encoding default in the RSE profile, use an encoding tag with Upload and Download MVS commands, use "),f=e("code",null,".gitattributes",-1),b=n(" files for uploading and downloading files from UNIX System Services, and use mappings files either provided by the RSE API host component or used at a project level. See "),y={href:"https://www.ibm.com/docs/en/developer-for-zos/16.0?topic=mapping-supported-host-code-pages",target:"_blank",rel:"noopener noreferrer"},w=n("this page with the list of all the supported code pages"),k=n("."),_=a(`<h2 id="zowe-capabilities" tabindex="-1"><a class="header-anchor" href="#zowe-capabilities" aria-hidden="true">#</a> Zowe capabilities</h2><p>When you work with z/OS\xAE resources through Zowe Explorer or Zowe CLI, character conversion between UTF-8 (the default encoding used by VS Code and the <strong>only</strong> local encoding for which correct conversion is currently guaranteed) and EBCDIC code pages is handled automatically by the z/OSMF and RSE API servers. Files stored on z/OS in EBCDIC are converted to UTF-8 when downloaded for display and editing in VS Code, and UTF-8 files are converted back to EBCDIC when uploaded to z/OS. To ensure accurate conversion, you must configure which EBCDIC code page corresponds to each z/OS resource. The following sections describe the various methods for specifying code page mappings for use with Zowe Explorer or Zowe CLI.</p><h3 id="zowe-cli" tabindex="-1"><a class="header-anchor" href="#zowe-cli" aria-hidden="true">#</a> Zowe CLI</h3><p>Many commands for Zowe CLI as well as the IBM RSE API Plug-in for Zowe CLI have additional parameters for specifying a code page directly or specifying a mappings file to be used for computing the code page encoding.</p><p>For example, assuming the member <code>SAM1</code> was written and stored on MVS using the IBM-273 EBCDIC encoding, you can work with it via the following commands.</p><ul><li><p>To download the member <code>SAM1</code> as a UTF-8 file (converting from IBM-273), issue the following command:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>zowe rse download ds <span class="token string">&quot;IBMUSER.SAMPLE.COBOL(SAM1)&quot;</span> --ec IBM-273
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>To upload the member <code>SAM1</code> using the IBM-273 EBCDIC encoding, issue the following command:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code> zowe rse upload ftds ./ibmuser/sample/cobol/SAM1.txt <span class="token string">&quot;IBMUSER.SAMPLE.COBOL(SAM1)&quot;</span> --ec IBM-273
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul><h3 id="zowe-profile-default-encoding" tabindex="-1"><a class="header-anchor" href="#zowe-profile-default-encoding" aria-hidden="true">#</a> Zowe Profile default encoding</h3><p>You can also provide a default encoding value to be used for your Zowe CLI commands as well as Zowe Explorer operations in your Zowe profiles themselves. To do that, complete the following steps:</p>`,8),v=n("Create or open your "),I=n("Zowe team configuration file"),S=n("."),x=e("li",null,[e("p",null,'Insert the encoding property under the "properties" object of the relevant profile.')],-1),C=a(`<p>Following is an example of how to do this:</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;profiles&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token property">&quot;rse&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
      <span class="token property">&quot;type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;rse&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;properties&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token property">&quot;port&quot;</span><span class="token operator">:</span> <span class="token number">6802</span><span class="token punctuation">,</span>
        <span class="token property">&quot;basePath&quot;</span><span class="token operator">:</span> <span class="token string">&quot;rseapi&quot;</span><span class="token punctuation">,</span>
        <span class="token property">&quot;protocol&quot;</span><span class="token operator">:</span> <span class="token string">&quot;https&quot;</span><span class="token punctuation">,</span>
        <span class="token property">&quot;encoding&quot;</span><span class="token operator">:</span> <span class="token string">&quot;IBM-930&quot;</span>
      <span class="token punctuation">}</span><span class="token punctuation">,</span>
      <span class="token property">&quot;secure&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;user&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;password&quot;</span><span class="token punctuation">]</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h2 id="advanced-ibm-rse-api-capabilities" tabindex="-1"><a class="header-anchor" href="#advanced-ibm-rse-api-capabilities" aria-hidden="true">#</a> Advanced IBM RSE API capabilities</h2><p>The RSE API Server provides the capability to manage mappings files that allow defining how MVS files should be converted when uploaded and downloaded. These mappings do not cover z/OS UNIX System Services, but see <a href="#character-conversion-using-gitattributes">Character conversion using <code>.gitattributes</code></a> instead.</p>`,4),E=n("The RSE CLI plug-in provides the ability to download a default mappings file from the server. This file is maintained by the RSE API server administrator and can be retrieved using the "),q=n("RSE CLI plug-in command"),B=n(),M=e("code",null,"zowe rse check conversion-mappings",-1),z=n(". You can modify this file in the "),O=e("code",null,"~/.zowe/profiles/rse",-1),P=n(" folder, and the tools automatically use the updated mappings file when they interact with the server. The mapping behavior is consistent with similar functionality offered in IBM Developer for z/OS through its user interface."),A=a(`<p>To download the default mappings file provided by your RSE API server administrator, issue the following command:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>zowe rse check conversion-mappings
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The downloaded mappings file will be placed in <code>~/.zowe/profiles/rse/conversion-mappings.json</code>. You can add your personal conversion preferences to this file and the updates will be automatically used by all your RSE CLI plug-in commands without the need to specify a command line parameter.</p><p>However, if you manage more than one such file, for example for different projects, or you even prefer defining such mappings in a ZAPP file, then you can specify the file to use with a command line parameter as well:</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code>zowe rse upload ftds ./ibmuser/sample/cobol/SAM1.txt <span class="token string">&quot;IBMUSER.SAMPLE.COBOL(SAM1)&quot;</span> --maps ./zapp.yaml
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>In addition to mappings files that are stored in the user&#39;s <code>.zowe</code> directory and used by the RSE CLI plug-in, <a href="./zapp">ZAPP</a> provides the same ability of defining mappings using the same schema, but offers YAML as additional syntax. This allows teams to share these mappings for their applications and make them part of the source code that could be stored in a Git repository or other SCM. ZAPP files can either be in YAML or JSON syntax; however, it is recommended to have your ZAPP file in one syntax only, not both, within the same project or directory.</p><h3 id="mvs-encoding-precedence-rules" tabindex="-1"><a class="header-anchor" href="#mvs-encoding-precedence-rules" aria-hidden="true">#</a> MVS encoding precedence rules</h3><p>Tools such as the RSE CLI plug-in or Z Open Editor find mappings following these precedence rules with some rules applied to CLI only:</p><ol><li>(CLI only) An <code>encoding | ec</code> parameter provided by the command should always have highest precedence, for example <code>--encoding IBM-273</code>.</li><li>(CLI only) An encoding found in a file that was provided via the parameter <code>mappings-file | maps</code>, for example <code>--mappings-file ~/myproject/zapp.yaml</code>.</li><li>An encoding found in the current workspace in a file named <code>zapp.yaml</code> or <code>zapp.json</code>.</li><li>An encoding found in the default mappings file in the user&#39;s <code>~/.zowe/profiles/rse</code> folder that was downloaded via command line.</li><li>An encoding specified in the Zowe CLI profile itself.</li><li>No encoding is specified, resulting in the use of the server default mappings file residing on the server.</li></ol><h3 id="mappings-file-schema" tabindex="-1"><a class="header-anchor" href="#mappings-file-schema" aria-hidden="true">#</a> Mappings file schema</h3><p>The JSON schema for defining RSE CLI plug-in profiles simply consists of an array of mappings and a default encoding to be used if none of the mappings provided apply. The mappings can be provided as a simple array called <code>mappings</code> of mappings objects in a JSON file or as part of a ZAPP profile with settings as shown in the diagram below. See examples further below.</p><p><img src="`+u+'" alt="Fig.1: ZAPP Schema Model for RSE API"><strong>Fig.1: ZAPP Schema Model for RSE API</strong></p><p>When reading these mappings the following validation and interpretation rules apply:</p><ul><li>There can only be one ZAPP <code>rse-mappings</code> profile of type <code>rseapi</code> in a ZAPP file.</li><li>Member mappings consist of the same properties as the mappings except for the member mappings itself, that is, only one level of nesting.</li><li>When member mappings are matched, they will override values of the parent mappings. For example, the parent data set mapping might define a default encoding that is true for members that do not match, but if a member mapping is valid, any encoding value specified there will override the parent mapping.</li><li>The <code>resource</code> property is a mandatory property for data set and member mappings. <strong>Note</strong>: Mapping against members in all data sets is not possible for performance reasons.</li><li>The <code>resource</code> of the data set parent represents a pattern on the data set name.</li><li>The <code>resource</code> of the member mapping represents a pattern on the member name.</li><li>If no <code>transfer</code> is specified for a resource mapping, the default is text.</li><li>If no <code>encoding</code> is defined for text, it will use the default specified in the local mappings file. If that is missing, it will use the default of the server.</li><li>If a <code>transfer</code> is specified as binary, the encoding will be ignored.</li><li>The <code>extension</code> property is only used for downloading files to determine which extension to append to the member name, which is to ensure editors can open the file correctly. For uploading files, only the mappings to resources are relevant.</li><li>An <code>extension</code> entry can be present either in a member mapping or the data set mapping. If it is in both mappings, the member mapping takes precedence. If it is missing completely in mappings, the first resource match will be used.</li></ul>',14),L=n("Resources can be specified following the rules defined in Step 5 of the z/OS Explorer docs for "),R={href:"https://www.ibm.com/docs/en/developer-for-zos/16.0?topic=mapping-data-sets-partitioned-data-set-members",target:"_blank",rel:"noopener noreferrer"},T=n("Mapping data sets and partitioned data set members"),Z=n("."),U=a(`<p>There are two wildcards allowed: <code>**</code> and <code>*</code></p><ul><li><code>**</code> matches in data set names across multiple name hierarchies. It cannot be used for member names. For example: <code>**ERROR**</code> matches: <ul><li><code>USER.ERROR.TEST</code></li><li><code>USER.A.B.MYERROR.ABC</code></li><li><code>USER.A.B.MYERROR2.ABC</code></li></ul></li><li><code>*</code> matches within a data set name segment or the member name. For example, <code>USER**COB*</code> matches: <ul><li><code>USER.A.COB</code></li><li><code>USER.A.B.COBOL</code></li><li><code>USER.A.B.ACOBCOPY</code></li></ul></li></ul><h3 id="example-json-mappings-file" tabindex="-1"><a class="header-anchor" href="#example-json-mappings-file" aria-hidden="true">#</a> Example JSON mappings file</h3><p>The following shows a sample mappings file using JSON that you could place in your <code>~/.zowe/profiles/rse</code> as <code>conversion-mappings.json</code>:</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;mappings&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span>
    <span class="token punctuation">{</span>
      <span class="token property">&quot;resource&quot;</span><span class="token operator">:</span> <span class="token string">&quot;**.SAMPLE.COB**&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;extension&quot;</span><span class="token operator">:</span> <span class="token string">&quot;cbl&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;transfer&quot;</span><span class="token operator">:</span> <span class="token string">&quot;text&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;encoding&quot;</span><span class="token operator">:</span> <span class="token string">&quot;IBM-273&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;memberMappings&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span>
        <span class="token punctuation">{</span>
          <span class="token property">&quot;extension&quot;</span><span class="token operator">:</span> <span class="token string">&quot;dat&quot;</span><span class="token punctuation">,</span>
          <span class="token property">&quot;transfer&quot;</span><span class="token operator">:</span> <span class="token string">&quot;binary&quot;</span><span class="token punctuation">,</span>
          <span class="token property">&quot;resource&quot;</span><span class="token operator">:</span> <span class="token string">&quot;EIC*&quot;</span>
        <span class="token punctuation">}</span>
      <span class="token punctuation">]</span>
    <span class="token punctuation">}</span><span class="token punctuation">,</span>
    <span class="token punctuation">{</span>
      <span class="token property">&quot;resource&quot;</span><span class="token operator">:</span> <span class="token string">&quot;**PLI*&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;extension&quot;</span><span class="token operator">:</span> <span class="token string">&quot;pl1&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;transfer&quot;</span><span class="token operator">:</span> <span class="token string">&quot;text&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;encoding&quot;</span><span class="token operator">:</span> <span class="token string">&quot;IBM-500&quot;</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">]</span><span class="token punctuation">,</span>
  <span class="token property">&quot;default.encoding&quot;</span><span class="token operator">:</span> <span class="token string">&quot;IBM-1047&quot;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><p>This file defines that data sets containing the string <code>.SAMPLE.COB</code> in their fully qualified name, such as <code>USER1.SAMPLE.COBOL</code>, are transferred as text with the IBM-273 EBCDIC code page (Austria/Germany) on MVS. When you download a data set member with an RSE CLI plug-in command or Zowe Explorer using an RSE profile, RSE API converts the content from IBM-273 EBCDIC to UTF-8, the format required by Z Open Editor. Uploading such a file converts the UTF-8 back to IBM-273 EBCDIC. The <code>extension</code> property, currently supported only by the CLI, specifies that the downloaded data set member is stored as a file with a <code>.cbl</code> file extension.</p><p>In addition to the default rule for <code>**.SAMPLE.COB**</code> data sets, a nested <code>memberMappings</code> subrule provides a refinement: If the member name contains <code>EIC</code> as a substring, the file is not converted from IBM-273 but treated as binary instead. This enables data sets to contain members of different types.</p><p>The example shows how members in data sets with names containing <code>PLI</code> are converted using IBM-500 (Belgium/Canada/Switzerland). In all other cases, the default conversion code page is IBM-1047.</p><h3 id="example-zapp-file" tabindex="-1"><a class="header-anchor" href="#example-zapp-file" aria-hidden="true">#</a> Example ZAPP file</h3><p>In a <code>zapp.yaml</code> file, you can specify the same mapping described in the previous section by defining a ZAPP profile of type <code>rseapi</code>. The <code>zapp.yaml</code> for this particular specification would contain text as follows:</p><div class="language-yaml ext-yml line-numbers-mode"><pre class="language-yaml"><code><span class="token key atrule">name</span><span class="token punctuation">:</span> sam
<span class="token key atrule">version</span><span class="token punctuation">:</span> 1.1.0

<span class="token key atrule">profiles</span><span class="token punctuation">:</span>
  <span class="token punctuation">-</span> <span class="token key atrule">name</span><span class="token punctuation">:</span> RSE<span class="token punctuation">-</span>Mappings
    <span class="token key atrule">type</span><span class="token punctuation">:</span> rseapi
    <span class="token key atrule">settings</span><span class="token punctuation">:</span>
      <span class="token key atrule">mappings</span><span class="token punctuation">:</span>
        <span class="token punctuation">-</span> <span class="token key atrule">resource</span><span class="token punctuation">:</span> <span class="token string">&quot;**.SAMPLE.COB**&quot;</span>
          <span class="token key atrule">extension</span><span class="token punctuation">:</span> cbl
          <span class="token key atrule">transfer</span><span class="token punctuation">:</span> text
          <span class="token key atrule">encoding</span><span class="token punctuation">:</span> IBM<span class="token punctuation">-</span><span class="token number">273</span>
          <span class="token key atrule">memberMappings</span><span class="token punctuation">:</span>
            <span class="token punctuation">-</span> <span class="token key atrule">extension</span><span class="token punctuation">:</span> dat
              <span class="token key atrule">transfer</span><span class="token punctuation">:</span> binary
              <span class="token key atrule">resource</span><span class="token punctuation">:</span> <span class="token string">&quot;*DAT&quot;</span>
        <span class="token punctuation">-</span> <span class="token key atrule">resource</span><span class="token punctuation">:</span> <span class="token string">&quot;**PLI*&quot;</span>
          <span class="token key atrule">extension</span><span class="token punctuation">:</span> pl1
          <span class="token key atrule">transfer</span><span class="token punctuation">:</span> text
          <span class="token key atrule">encoding</span><span class="token punctuation">:</span> IBM<span class="token punctuation">-</span><span class="token number">500</span>
      <span class="token key atrule">default.encoding</span><span class="token punctuation">:</span> IBM<span class="token punctuation">-</span><span class="token number">1047</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><h3 id="using-mappings-files-with-z-open-editor" tabindex="-1"><a class="header-anchor" href="#using-mappings-files-with-z-open-editor" aria-hidden="true">#</a> Using mappings files with Z Open Editor</h3>`,12),D=n("Mappings files are not only used by RSE CLI plug-in commands, but also by Z Open Editor remote include file resolution operations. When you define a property group either in your "),F=n("ZAPP"),j=n(" file or "),V=e("a",{href:"./setting_propertygroup"},"Settings",-1),N=n(", the retrieval of include files or copybooks will use mappings files based on the precedence rules defined above. For example, if you define mappings in a "),W=e("code",null,"zapp.yaml",-1),Y=n(" file in your workspace, these mappings will be used. If you do not have a ZAPP file, but have a personal mappings file in "),J=e("code",null,"~/.zowe/profiles/rse/conversion-mappings.json",-1),X=n(", the personal file will be automatically used."),G=e("h3",{id:"using-mappings-files-with-zowe-explorer",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#using-mappings-files-with-zowe-explorer","aria-hidden":"true"},"#"),n(" Using mappings files with Zowe Explorer")],-1),H=n("Zowe Explorer enables you to navigate your data sets and open data set members in the editor with a simple click. When you use Zowe Explorer with an RSE profile, conversion mappings are applied as well. To enable this, specify the absolute location of the mappings file in your user settings. The setting is called "),K=e("code",null,"zopeneditor.zowe.defaultRseConversionMappingsFile",-1),Q=n(". You can find it in the IBM Z Open Editor settings together with the other "),$=n("Zowe-related settings"),ee=n(", such as the "),ne=e("code",null,"defaultCliProfile",-1),se=n(". Conversion mappings defined in either a JSON-formatted RSE API user mappings file or a ZAPP file override an encoding specified in a Zowe profile."),ae=a('<h3 id="rse-cli-plug-in-logging" tabindex="-1"><a class="header-anchor" href="#rse-cli-plug-in-logging" aria-hidden="true">#</a> RSE CLI plug-in logging</h3><p>When using encoding and mappings files with the RSE CLI plug-in commands, logging will be written and found at <code>~/.zowe/zowe/logs/zowe.log</code>. This log file will contain details about the encoding precedence that was used during upload and download of MVS files, the location of the mappings file if available, and the outcome of the encoding or transfer type that was chosen according to the previously-mentioned values.</p><p>In addition to the logging, you can also refer to the Upload and Download output to troubleshoot. If binary transfer was used, the output includes a binary value of <code>true</code>. If the file was transferred as text and an encoding value was used, the output includes an encoding value for each file.</p><h2 id="specifying-an-ebcdic-file-encoding-to-use-with-the-language-servers" tabindex="-1"><a class="header-anchor" href="#specifying-an-ebcdic-file-encoding-to-use-with-the-language-servers" aria-hidden="true">#</a> Specifying an EBCDIC file encoding to use with the language servers</h2><p>While the previous sections covered character conversion during file transfer between your local workspace and z/OS resources, the language servers operate entirely within Z Open Editor. You can specify an EBCDIC code page for the language servers to use when they parse your programs. This enables the language servers to parse programs in their source code page, ensuring accurate syntax validation and line-length calculations. The specified encoding must match the code page used when the file is stored on z/OS. This functionality is available for the COBOL, PL/I, and JCL language servers:</p>',5),oe=e("p",null,[n("For local COBOL, PL/I, or JCL programs, configure the "),e("code",null,"zopeneditor.encodings.filePatterns"),n(" settings object.")],-1),te=n("This setting maps file name glob patterns to an EBCDIC file encoding. These patterns are specified as glob patterns. A single asterisk "),ie=e("code",null,"*",-1),re=n(" matches any number of characters within a path segment, including none. A double asterisk "),pe=e("code",null,"**",-1),le=n(" matches any number of path segments, including none. For example, "),ce=e("code",null,"{ **/COBOL/*.cbl : IBM-930 }",-1),de=n(" assigns any file paths that contain a directory named "),ue=e("code",null,"COBOL",-1),he=n(" and end with a "),me=e("code",null,".cbl",-1),ge=n(" extension an encoding of "),fe=e("code",null,"IBM-930",-1),be=n(". ("),ye={href:"https://code.visualstudio.com/docs/editor/glob-patterns",target:"_blank",rel:"noopener noreferrer"},we=n("Learn more about how to specify glob patterns."),ke=n(")"),_e=e("p",null,"For remote programs (accessed through Zowe Explorer), you can do any of the following:",-1),ve=a('<li>If an RSE API profile is used to access the file (such as a data set opened in Zowe Explorer), Z Open Editor first looks for an encoding specified by your RSE mappings as documented <a href="#advanced-ibm-rse-api-capabilities">above</a> (either in a <code>rseapi</code> profile in your <code>zapp.yaml</code> or the location in the <code>zopeneditor.zowe.defaultRseConversionMappingsFile</code> setting).</li><li>If no RSE mappings exist or if you are using a z/OSMF profile to access the file, you can specify an encoding in the Zowe Explorer profile you are using to access the program (see the <code>encoding</code> property example in this <a href="#zowe-capabilities">section</a>).</li>',2),Ie=n("You can use the "),Se=e("code",null,"zopeneditor.encodings.filePatterns",-1),xe=n(" user setting for remote files, but you must adjust the glob pattern to match to remote files in the Zowe Explorer filesystem (described "),Ce=n("here"),Ee=n(")."),qe=e("p",null,[n("These settings only control what encodings are passed to the language servers. To control the encodings used for file conversions when you upload or download z/OS resources, use an "),e("a",{href:"#advanced-ibm-rse-api-capabilities"},"RSE API mappings file"),n(", a "),e("code",null,"rseapi"),n(" ZAPP profile, or specify the "),e("a",{href:"#zowe-profile-default-encoding"},[e("code",null,"encoding"),n(" property in your Zowe profile")]),n(".")],-1),Be=e("p",null,'When a program is opened with an encoding specified using one of the preceding methods, a counter titled "EBCDIC Byte Count" appears in the VS Code status bar. This counter displays two numbers:',-1),Me=e("li",null,"The number of bytes in the line at the cursor's current position (accounting for the source code page).",-1),ze=n("The maximum number of bytes enabled in the line (controlled by the "),Oe=e("code",null,"zopeneditor.language.maximumLineLength",-1),Pe=n(" setting). As with the previous functionality, this counter displays for COBOL, PL/I, and JCL programs."),Ae=a('<p>If the language server detects double-byte characters, it displays guillemets (\xBB\xAB) at the positions of the SOSI codes, when applicable. These guillemets are decorative; they are not stored with the program and do not affect line length. The byte counter, along with SOSI position detection and decoration, is supported for COBOL, PL/I, and JCL programs that are assigned an EBCDIC file encoding.</p><h2 id="character-conversion-using-gitattributes" tabindex="-1"><a class="header-anchor" href="#character-conversion-using-gitattributes" aria-hidden="true">#</a> Character conversion using <code>.gitattributes</code></h2><p>The <code>.gitattributes</code> file allows you to specify how files should be encoded when they are checked out to the working directory and when they are stored in the Git repository. This is particularly useful for handling double-byte characters.</p><h3 id="how-it-works" tabindex="-1"><a class="header-anchor" href="#how-it-works" aria-hidden="true">#</a> How it works</h3><ol><li><strong>User build from VS Code</strong>: When you perform a user build on an existing COBOL file that contains double-byte characters, the <code>.gitattributes</code> settings ensure that the file is encoded in IBM-930 when it is checked out to the working directory.</li><li><strong>Build process</strong>: During the build process, the file is uploaded to the specified UNIX System Services folder with the encoding specified in <code>.gitattributes</code>.</li><li><strong>File display in VS Code</strong>: When you open the uploaded files in VS Code through the [z/OS Resources Table](./advanced_resource_table.md or Zowe Explorer), the double-byte characters are converted from IBM-930 to UTF-8 during download for display in the text editor. The source file on z/OS remains unmodified.</li></ol><h3 id="example-workflow" tabindex="-1"><a class="header-anchor" href="#example-workflow" aria-hidden="true">#</a> Example workflow</h3><ol><li>Update the <code>.gitattributes</code> file located at the root of the repository with the following line. This specifies an encoding of IBM-930 for all files in the repository with the <code>.cbl</code> file extension: <code>*.cbl zos-working-tree-encoding=ibm-930 git-encoding=utf-8</code>.</li><li>Perform a user build from VS Code on an existing COBOL file that contains double-byte characters.</li><li>During the build process, the <code>zos-working-tree-encoding</code> parameter specifies the code page used to encode files that are uploaded to UNIX System Services or MVS during the build.</li><li>Wait for the build process to complete. Once finished, the COBOL file should be uploaded to the specified USS folder using the encoding from <code>.gitattributes</code>.</li></ol>',7);function Le(Re,Te){const i=r("ExternalLinkIcon"),o=r("RouterLink");return p(),l(c,null,[m,e("p",null,[g,f,b,e("a",y,[w,s(i)]),k]),_,e("ol",null,[e("li",null,[e("p",null,[v,s(o,{to:"/Docs/zowe_explorer_v2.html#creating-zowe-v2-team-configuration-files"},{default:t(()=>[I]),_:1}),S])]),x]),C,e("p",null,[E,s(o,{to:"/Docs/rse_cli_command.html#system"},{default:t(()=>[q]),_:1}),B,M,z,O,P]),A,e("p",null,[L,e("a",R,[T,s(i)]),Z]),U,e("p",null,[D,s(o,{to:"/Docs/zapp.html#a-zapp-file-example"},{default:t(()=>[F]),_:1}),j,V,N,W,Y,J,X]),G,e("p",null,[H,K,Q,s(o,{to:"/Docs/interact_zos_zowe_explorer.html#using-rse-api-in-zowe-explorer"},{default:t(()=>[$]),_:1}),ee,ne,se]),ae,e("ol",null,[e("li",null,[oe,e("ul",null,[e("li",null,[te,ie,re,pe,le,ce,de,ue,he,me,ge,fe,be,e("a",ye,[we,s(i)]),ke])])]),e("li",null,[_e,e("ol",null,[ve,e("li",null,[Ie,Se,xe,s(o,{to:"/Docs/setting_fileassociations.html#remote-file-associations"},{default:t(()=>[Ce]),_:1}),Ee])])])]),qe,Be,e("ul",null,[Me,e("li",null,[ze,s(o,{to:"/Docs/setting_maximum_line_length.html"},{default:t(()=>[Oe]),_:1}),Pe])]),Ae],64)}var De=d(h,[["render",Le]]);export{De as default};
